import { MjmlColumn, MjmlSection, MjmlText } from "@faire/mjml-react";

import { defaultTheme } from "@/components/email/theme-default";
import type { EmailThemeTokens } from "@/components/email/theme-default";
import {
  CTACopy,
  CTAEmailShell,
} from "@/components/email/cta-shared";

export type CTAWithTitleAndActionLeadVariant =
  | "title-and-lead"
  | "secondary-button"
  | "minimal";

export interface CTAWithTitleAndActionLeadProps {
  theme?: EmailThemeTokens;
  heading?: string;
  subtext?: string;
  ctaLabel?: string;
  ctaHref?: string;
  secondaryCtaLabel?: string;
  secondaryCtaHref?: string;
  signoff?: string;
  pageBackgroundColor?: string;
  backgroundColor?: string;
  headingColor?: string;
  textColor?: string;
  primaryButtonBackgroundColor?: string;
  primaryButtonTextColor?: string;
  secondaryButtonBackgroundColor?: string;
  secondaryButtonTextColor?: string;
  secondaryButtonBorderColor?: string;
  variant?: CTAWithTitleAndActionLeadVariant;
}

const fontFamily =
  'Inter, ui-sans-serif, system-ui, -apple-system, "Segoe UI", sans-serif';

export const CTAWithTitleAndActionLeadSection = (
  props: Omit<CTAWithTitleAndActionLeadProps, "theme">
) => {
  const {
    backgroundColor,
    ctaHref,
    ctaLabel,
    heading,
    headingColor,
    primaryButtonBackgroundColor,
    primaryButtonTextColor,
    secondaryButtonBorderColor,
    secondaryButtonTextColor,
    secondaryCtaHref,
    secondaryCtaLabel,
    signoff,
    subtext,
    textColor,
    variant,
  } = {
    backgroundColor: "#fffffe",
    ctaHref: "https://example.com/",
    heading: "Confirm your email",
    headingColor: "#030712",
    primaryButtonBackgroundColor: "#4f46e5",
    primaryButtonTextColor: "#f8fafc",
    secondaryButtonBorderColor: "#d1d5db",
    secondaryButtonTextColor: "#4b5563",
    secondaryCtaHref: "https://example.com/",
    secondaryCtaLabel: "Learn more",
    signoff: "Thank you, the emailcn Team",
    subtext:
      "We created a personal account for you. Please confirm your e-mail address and use our service to the maximum",
    textColor: "#4b5563",
    variant: "title-and-lead",
    ...props,
  };
  let defaultCtaLabel = "Shop now";
  if (variant === "title-and-lead") {
    defaultCtaLabel = "Activate account";
  } else if (variant === "minimal") {
    defaultCtaLabel = "Shop now →";
  }

  return (
    <MjmlSection backgroundColor={backgroundColor} padding="44px 24px">
      <MjmlColumn padding="0">
        <CTACopy
          align={variant === "title-and-lead" ? "left" : "center"}
          ctaHref={ctaHref}
          ctaLabel={ctaLabel ?? defaultCtaLabel}
          heading={heading}
          headingColor={headingColor}
          primaryButtonBackgroundColor={primaryButtonBackgroundColor}
          primaryButtonTextColor={primaryButtonTextColor}
          secondaryButtonBorderColor={secondaryButtonBorderColor}
          secondaryButtonTextColor={secondaryButtonTextColor}
          secondaryCtaHref={secondaryCtaHref}
          secondaryCtaLabel={
            variant === "secondary-button" ? secondaryCtaLabel : undefined
          }
          subtext={subtext}
          textColor={textColor}
        />
        {variant === "title-and-lead" ? (
          <MjmlText
            color={textColor}
            fontFamily={fontFamily}
            fontSize="14px"
            lineHeight="20px"
            padding="28px 0 0"
          >
            {signoff}
          </MjmlText>
        ) : null}
      </MjmlColumn>
    </MjmlSection>
  );
};

export const CTAWithTitleAndActionLead = ({
  pageBackgroundColor = "#f1f5f9",
  theme = defaultTheme,
  ...props
}: CTAWithTitleAndActionLeadProps) => (
  <CTAEmailShell
    pageBackgroundColor={pageBackgroundColor}
    preview="Confirm your email"
    theme={theme}
  >
    <CTAWithTitleAndActionLeadSection {...props} />
  </CTAEmailShell>
);

CTAWithTitleAndActionLead.PreviewProps = {
  theme: defaultTheme,
  variant: "title-and-lead",
} satisfies CTAWithTitleAndActionLeadProps;
